var antigel = global.get('antigel') || 'off';
if (antigel == 'off') {
    // Sauvegarder la vitesse courante avant de passer en antigel
    var current_speed = global.get('filtration_speed') || 'STOP';
    global.set('antigel_previous_speed', current_speed);
    global.set('antigel', 'on');
    msg.payload = '100'; // forcer 100%
    return msg;
}
else
    return null;

var antigel = global.get('antigel') || 'off';
if (antigel == 'on') {
    global.set('antigel', 'off');
    // Reprendre la vitesse précédente
    var previous_speed = global.get('antigel_previous_speed') || 'STOP';
    msg.payload = previous_speed;
    return msg;
}
else
    return null;

var antigel = global.get('antigel');
msg.from = 'lionel@beard.fr';
if (antigel == 'on') {
    msg.topic = '[Piscine] Début anti-gel';
    msg.payload = 'Mode anti-gel enclenché';
} else {
    msg.topic = '[Piscine] Fin anti-gel';
    msg.payload = 'Mode anti-gel stoppé';
}
return msg;

var antigel = global.get('antigel') || 'off';
if (antigel == 'off') {
    global.set('antigel', 'on')
    msg.payload = 'ON'
    return msg;
}
else
    return null;

var antigel = global.get('antigel') || 'off';
if (antigel == 'on') {
    global.set('antigel', 'off')
    msg.payload = 'OFF'
    return msg;
}
else
    return null;

var antigel = global.get('antigel');
msg.payload = antigel;

return msg;

// ============================================================
// GESTION VITESSE POMPE VERDON VS
// Topic MQTT : piscine/filtration/speed
// Valeurs : STOP, 52, 75, 100
// Mapping relais : R1=STOP, R2=52%, R3=75%, R4=100%
// ============================================================

var speed = msg.payload.toString().trim().toUpperCase();
var antigel = global.get('antigel') || 'off';

// Sécurité antigel : ignorer STOP si antigel actif
if (antigel === 'on' && speed === 'STOP') {
    node.warn('Antigel actif, commande STOP ignorée');
    return null;
}

var relayMap = { 'STOP': 1, '52': 2, '75': 3, '100': 4 };
var relay = relayMap[speed];

if (!relay) {
    node.warn('Vitesse inconnue : ' + speed);
    return null;
}

// Sauvegarde vitesse courante
global.set('filtration_speed', speed);

// Ouvrir relai cible en premier
var msgs = [{ payload: '-o ' + relay + ' /dev/ttyUSB0' }];

// Fermer tous les autres relais pompe
[1, 2, 3, 4]
    .filter(r => r !== relay)
    .forEach(r => msgs.push({ payload: '-c ' + r + ' /dev/ttyUSB0' }));

// Sortie 2 : notification
var notif = {
    topic: speed === 'STOP' 
        ? 'Filtration arrêtée' 
        : 'Filtration démarrée à ' + speed + '%',
    payload: speed
};

return [msgs, notif];

// ============================================================
// GESTIONNAIRE QUEUE RELAIS
// Garantit l'ordre et évite les appels simultanés
// ============================================================

var queue = flow.get('relay_queue') || [];
var running = flow.get('relay_running') || false;

queue.push(msg.payload);
flow.set('relay_queue', queue);

if (running) {
    return null;
}

flow.set('relay_running', true);
var cmd = queue.shift();
flow.set('relay_queue', queue);
msg.payload = cmd;
return msg;

// ============================================================
// FIN DE COMMANDE - Lance la suivante si queue non vide
// ============================================================

var queue = flow.get('relay_queue') || [];

if (queue.length === 0) {
    flow.set('relay_running', false);
    return null;
}

var cmd = queue.shift();
flow.set('relay_queue', queue);
msg.payload = cmd;
return msg;

// ============================================================
// CONSTRUCTION DU STATUS FILTRATION
// Lit l'état des relais + vitesse courante depuis global
// ============================================================

var speed = global.get('filtration_speed') || 'STOP';

msg.payload = '-s 1 /dev/ttyUSB0';
msg.speed = speed;
return msg;

// ============================================================
// PARSE STATUS RELAIS
// Construit un objet status complet
// ============================================================

var raw = msg.payload.replace(/\s+/g, ' ').trim();
var speed = msg.speed || global.get('filtration_speed') || 'STOP';

msg.payload = JSON.stringify({
    speed: speed,
    relay_status: raw,
    running: speed !== 'STOP',
    timestamp: new Date().toISOString()
});

return msg;

// ============================================================
// PRÉPARATION NOTIFICATION PUSHOVER
// ============================================================

var speed = msg.payload.toString();

if (speed === 'STOP') {
    msg.topic = 'Filtration arrêtée';
} else {
    msg.topic = 'Filtration démarrée à ' + speed + '%';
}

return msg;

var status = JSON.parse(msg.payload);
msg.payload = status.running ? 'ON' : 'OFF';
return msg;

// fn_resync — compare état attendu vs état réel
var expected_speed = global.get('filtration_speed') || 'STOP';
var last_sync = context.get('last_sync') || '';

// Ne resynchroniser que si la vitesse a changé depuis dernière synchro
if (expected_speed === last_sync) {
    return null; // Pas de changement, rien à faire
}

// Mémoriser la dernière synchro
context.set('last_sync', expected_speed);

msg.payload = expected_speed;
msg.topic = 'piscine/filtration/speed';
return msg;

var antigel = global.get('antigel') || 'off';
if (antigel == 'off') {
    return msg;
}
else
    return null;

if (msg.payload == 'ON') {
    msg.topic = 'Filtration démarrée';
} else {
    msg.topic = 'Filtration arrêtée';
}
return msg;

var payload = msg.payload
if (payload == "ON") {
    msg.payload = "OFF"
}
else {
    msg.payload = "ON"
}
return msg;
